INSERT INTO recipes (id, title, category, cuisine, difficulty, time, servings, rating, reviews, image, description, ingredients, steps, featured, trending) VALUES ('1', 'Creamy Tuscan Garlic Chicken', 'Chicken Recipes', 'Italian', 'medium', '30 mins', 4, 4.8, 342, 'assets/images/tuscan-chicken.jpg', 'Tender pan-fried chicken breasts in a rich, creamy parmesan sauce with sun-dried tomatoes and spinach. A restaurant-quality meal ready in just 30 minutes.', '["2 large chicken breasts, sliced in half horizontally", "1 tbsp olive oil", "1 cup heavy cream", "1/2 cup chicken broth", "1 tsp garlic powder", "1 tsp italian seasoning", "1/2 cup parmesan cheese", "1 cup spinach, chopped", "1/2 cup sun-dried tomatoes"]', '["In a large skillet, heat oil over medium-high heat. Add chicken and cook until golden brown (about 5 minutes per side). Remove and set aside.", "In the same skillet, add the heavy cream, chicken broth, garlic powder, italian seasoning, and parmesan cheese. Whisk over medium heat until it starts to thicken.", "Add the spinach and sun-dried tomatoes to the skillet. Simmer until the spinach is wilted.", "Return the chicken to the skillet and coat with the sauce. Serve immediately over pasta or with crusty bread."]', 1, 1);
INSERT INTO recipes (id, title, category, cuisine, difficulty, time, servings, rating, reviews, image, description, ingredients, steps, featured, trending) VALUES ('2', 'Spicy Salmon Sushi Bowls', 'Fish & Seafood Recipes', 'Japanese', 'easy', '20 mins', 2, 4.9, 856, 'assets/images/sushi-bowl.jpg', 'All the flavors of a spicy salmon roll in an easy-to-assemble bowl. Fresh, healthy, and incredibly satisfying.', '["1 lb sushi-grade salmon, cubed", "2 cups cooked sushi rice", "1 avocado, sliced", "1 cucumber, diced", "2 tbsp soy sauce", "1 tbsp sesame oil", "2 tbsp spicy mayo", "1 tsp sesame seeds", "Nori sheets for serving"]', '["In a bowl, toss the cubed salmon with soy sauce and sesame oil. Let sit for 5 minutes.", "Divide the cooked sushi rice into two bowls.", "Top the rice with the marinated salmon, sliced avocado, and diced cucumber.", "Drizzle heavily with spicy mayo, sprinkle with sesame seeds, and serve with nori sheets."]', 1, 1);
INSERT INTO recipes (id, title, category, cuisine, difficulty, time, servings, rating, reviews, image, description, ingredients, steps, featured, trending) VALUES ('3', 'Classic Beef Wellington', 'International Non-Veg Dishes', 'British', 'hard', '2 hrs', 6, 4.7, 124, 'assets/images/wellington.jpg', 'A show-stopping centerpiece featuring perfectly seared beef tenderloin wrapped in a mushroom duxelles, prosciutto, and golden puff pastry.', '["2 lbs beef tenderloin center cut", "1 lb cremini mushrooms, finely chopped", "6 slices prosciutto", "1 sheet puff pastry, thawed", "2 tbsp dijon mustard", "1 egg, beaten", "Salt and pepper to taste"]', '["Season the beef generously. Sear in a hot pan on all sides until browned. Let cool, then brush with mustard.", "Cook the mushrooms in a dry pan until all moisture evaporates. Let cool.", "Lay out plastic wrap. Overlap prosciutto slices, spread mushrooms over them, and place beef in the center. Roll tightly and chill for 30 minutes.", "Wrap the chilled beef roll in puff pastry. Brush with egg wash and score the top.", "Bake at 400\u00b0F (200\u00b0C) for 25-35 minutes until pastry is golden and meat reaches desired doneness. Rest before slicing."]', 0, 0);
INSERT INTO recipes (id, title, category, cuisine, difficulty, time, servings, rating, reviews, image, description, ingredients, steps, featured, trending) VALUES ('4', 'Fluffy Japanese Pancakes', 'Pancakes & Waffles', 'Japanese', 'medium', '25 mins', 2, 4.6, 412, 'https://images.unsplash.com/photo-1528207776546-365bb710ee93?q=80&w=1470&auto=format&fit=crop', 'Cloud-like, jiggly soufflé pancakes that melt in your mouth. Serve with fresh berries and maple syrup.', '["2 large eggs, separated", "2 tbsp milk", "1/4 tsp vanilla extract", "1/4 cup cake flour", "1/2 tsp baking powder", "2 tbsp sugar"]', '["Whisk egg yolks, milk, and vanilla. Sift in flour and baking powder, whisk until smooth.", "In a separate clean bowl, beat egg whites until foamy. Gradually add sugar and beat until stiff peaks form.", "Gently fold the egg whites into the yolk mixture in three additions. Do not overmix.", "Heat a non-stick pan over very low heat. Scoop tall mounds of batter. Cover with a lid and cook for 4-5 minutes per side until golden.", "Serve immediately with butter and syrup."]', 1, 0);
INSERT INTO recipes (id, title, category, cuisine, difficulty, time, servings, rating, reviews, image, description, ingredients, steps, featured, trending) VALUES ('5', 'Butter Chicken', 'Chicken Recipes', 'Global', 'medium', '45 mins', 4, 4.5, 281, 'https://images.unsplash.com/photo-1604908176997-125f25cc6f3d?q=80&w=1613&auto=format&fit=crop', 'A delicious preparation of Butter Chicken, carefully crafted for the perfect meal.', '["1 lb Chicken, cut into pieces", "2 tbsp Cooking Oil or Butter", "1 Onion, finely chopped", "2 cloves Garlic, minced", "Chef''s special spice blend", "Fresh herbs for garnish", "Salt and pepper to taste"]', '["Prepare all ingredients by washing, peeling, and chopping as necessary.", "Heat oil or butter in a pan over medium heat. Saut\u00e9 the onions and garlic until fragrant.", "Add the main ingredient and cook until browned on all sides.", "Stir in the spices and season generously with salt and pepper.", "Add a splash of water or broth, cover, and simmer until fully cooked.", "Plate beautifully, garnish with fresh herbs, and serve hot."]', 0, 0);
INSERT INTO recipes (id, title, category, cuisine, difficulty, time, servings, rating, reviews, image, description, ingredients, steps, featured, trending) VALUES ('6', 'Chicken Biryani', 'Chicken Recipes', 'Global', 'medium', '45 mins', 4, 4.5, 479, 'https://images.unsplash.com/photo-1604908176997-125f25cc6f3d?q=80&w=1613&auto=format&fit=crop', 'A delicious preparation of Chicken Biryani, carefully crafted for the perfect meal.', '["1 lb Chicken, cut into pieces", "2 cups Basmati rice, washed and soaked", "2 large Onions, thinly sliced", "1/2 cup Yogurt", "2 tbsp Ginger-garlic paste", "2 tbsp Biryani masala", "Whole spices (cardamom, cloves, cinnamon)", "Mint and coriander leaves", "3 tbsp Ghee or Oil"]', '["Marinate the 1 lb chicken with yogurt, ginger-garlic paste, and spices for 1 hour.", "In a large pot, heat ghee and fry the whole spices and sliced onions until golden brown.", "Add the marinated mixture and cook until the oil begins to separate.", "In a separate pot, boil water with salt and whole spices, then parboil the soaked basmati rice (about 70% cooked).", "Layer the parboiled rice over the cooked mixture. Sprinkle mint leaves and saffron milk.", "Cover tightly and cook on low heat (dum) for 20-25 minutes. Serve hot."]', 0, 0);
INSERT INTO recipes (id, title, category, cuisine, difficulty, time, servings, rating, reviews, image, description, ingredients, steps, featured, trending) VALUES ('7', 'Chicken Curry', 'Chicken Recipes', 'Global', 'medium', '45 mins', 4, 4.5, 431, 'https://images.unsplash.com/photo-1604908176997-125f25cc6f3d?q=80&w=1613&auto=format&fit=crop', 'A delicious preparation of Chicken Curry, carefully crafted for the perfect meal.', '["1 lb Chicken, cut into pieces", "2 large Onions, finely chopped", "2 Tomatoes, pureed", "1 tbsp Ginger-garlic paste", "1 tsp Turmeric powder", "1 tsp Red chili powder", "1 tsp Garam masala", "2 tbsp Oil or Butter", "Salt to taste", "Fresh coriander leaves for garnish"]', '["Heat oil in a pan over medium heat. Add chopped onions and saut\u00e9 until golden brown.", "Add ginger-garlic paste and saut\u00e9 for another 2 minutes until fragrant.", "Pour in the tomato puree, turmeric, red chili powder, and salt. Cook until the mixture thickens and oil separates.", "Add the 1 lb chicken and coat well with the masala.", "Add half a cup of water, cover, and simmer until cooked through (about 15-20 minutes).", "Sprinkle garam masala and garnish with fresh coriander before serving."]', 0, 0);
INSERT INTO recipes (id, title, category, cuisine, difficulty, time, servings, rating, reviews, image, description, ingredients, steps, featured, trending) VALUES ('8', 'Chicken Tikka', 'Chicken Recipes', 'Global', 'medium', '45 mins', 4, 4.5, 160, 'https://images.unsplash.com/photo-1604908176997-125f25cc6f3d?q=80&w=1613&auto=format&fit=crop', 'A delicious preparation of Chicken Tikka, carefully crafted for the perfect meal.', '["1 lb Chicken, cut into pieces", "2 large Onions, finely chopped", "2 Tomatoes, pureed", "1 tbsp Ginger-garlic paste", "1 tsp Turmeric powder", "1 tsp Red chili powder", "1 tsp Garam masala", "2 tbsp Oil or Butter", "Salt to taste", "Fresh coriander leaves for garnish"]', '["Heat oil in a pan over medium heat. Add chopped onions and saut\u00e9 until golden brown.", "Add ginger-garlic paste and saut\u00e9 for another 2 minutes until fragrant.", "Pour in the tomato puree, turmeric, red chili powder, and salt. Cook until the mixture thickens and oil separates.", "Add the 1 lb chicken and coat well with the masala.", "Add half a cup of water, cover, and simmer until cooked through (about 15-20 minutes).", "Sprinkle garam masala and garnish with fresh coriander before serving."]', 0, 0);
