INSERT INTO recipes (id, title, category, cuisine, difficulty, time, servings, rating, reviews, image, description, ingredients, steps, featured, trending) VALUES ('14', 'Chicken Alfredo Pasta', 'Chicken Recipes', 'Global', 'medium', '45 mins', 4, 4.5, 287, 'https://images.unsplash.com/photo-1604908176997-125f25cc6f3d?q=80&w=1613&auto=format&fit=crop', 'A delicious preparation of Chicken Alfredo Pasta, carefully crafted for the perfect meal.', '["1 lb Fettuccine pasta", "1 lb Chicken breast, sliced", "1/2 cup Butter", "1 cup Heavy cream", "1 1/2 cups Parmesan cheese, grated", "2 cloves Garlic, minced", "Salt and black pepper to taste", "Fresh parsley for garnish"]', '["Boil fettuccine pasta in salted water until al dente. Drain and set aside.", "In a large skillet, melt a tablespoon of butter and cook the chicken until golden and cooked through. Remove and set aside.", "In the same skillet, melt the remaining butter. Add minced garlic and saut\u00e9 for 1 minute.", "Whisk in the heavy cream and let it simmer for 2 minutes.", "Gradually whisk in the parmesan cheese until the sauce is smooth and creamy.", "Season with salt and pepper. Add the cooked pasta and chicken back into the skillet and toss to coat.", "Garnish with fresh parsley and serve hot."]', 0, 1);
INSERT INTO recipes (id, title, category, cuisine, difficulty, time, servings, rating, reviews, image, description, ingredients, steps, featured, trending) VALUES ('15', 'Mutton Biryani', 'Mutton / Lamb Recipes', 'Global', 'medium', '45 mins', 4, 4.5, 446, 'https://images.unsplash.com/photo-1544025162-8111142154ea?q=80&w=1632&auto=format&fit=crop', 'A delicious preparation of Mutton Biryani, carefully crafted for the perfect meal.', '["1 lb Mutton, cut into pieces", "2 cups Basmati rice, washed and soaked", "2 large Onions, thinly sliced", "1/2 cup Yogurt", "2 tbsp Ginger-garlic paste", "2 tbsp Biryani masala", "Whole spices (cardamom, cloves, cinnamon)", "Mint and coriander leaves", "3 tbsp Ghee or Oil"]', '["Marinate the 1 lb mutton with yogurt, ginger-garlic paste, and spices for 1 hour.", "In a large pot, heat ghee and fry the whole spices and sliced onions until golden brown.", "Add the marinated mixture and cook until the oil begins to separate.", "In a separate pot, boil water with salt and whole spices, then parboil the soaked basmati rice (about 70% cooked).", "Layer the parboiled rice over the cooked mixture. Sprinkle mint leaves and saffron milk.", "Cover tightly and cook on low heat (dum) for 20-25 minutes. Serve hot."]', 0, 0);
INSERT INTO recipes (id, title, category, cuisine, difficulty, time, servings, rating, reviews, image, description, ingredients, steps, featured, trending) VALUES ('16', 'Rogan Josh', 'Mutton / Lamb Recipes', 'Global', 'medium', '45 mins', 4, 4.5, 306, 'https://images.unsplash.com/photo-1544025162-8111142154ea?q=80&w=1632&auto=format&fit=crop', 'A delicious preparation of Rogan Josh, carefully crafted for the perfect meal.', '["1 lb Mutton, cut into pieces", "2 large Onions, finely chopped", "2 Tomatoes, pureed", "1 tbsp Ginger-garlic paste", "1 tsp Turmeric powder", "1 tsp Red chili powder", "1 tsp Garam masala", "2 tbsp Oil or Butter", "Salt to taste", "Fresh coriander leaves for garnish"]', '["Heat oil in a pan over medium heat. Add chopped onions and saut\u00e9 until golden brown.", "Add ginger-garlic paste and saut\u00e9 for another 2 minutes until fragrant.", "Pour in the tomato puree, turmeric, red chili powder, and salt. Cook until the mixture thickens and oil separates.", "Add the 1 lb mutton and coat well with the masala.", "Add half a cup of water, cover, and simmer until cooked through (about 15-20 minutes).", "Sprinkle garam masala and garnish with fresh coriander before serving."]', 0, 0);
