INSERT INTO recipes (id, title, category, cuisine, difficulty, time, servings, rating, reviews, image, description, ingredients, steps, featured, trending) VALUES ('23', 'Fish Curry', 'Fish & Seafood Recipes', 'Global', 'medium', '45 mins', 4, 4.5, 247, 'https://images.unsplash.com/photo-1615141982883-c7da0e69f591?q=80&w=1470&auto=format&fit=crop', 'A delicious preparation of Fish Curry, carefully crafted for the perfect meal.', '["1 lb Fish fillets", "2 large Onions, finely chopped", "2 Tomatoes, pureed", "1 tbsp Ginger-garlic paste", "1 tsp Turmeric powder", "1 tsp Red chili powder", "1 tsp Garam masala", "2 tbsp Oil or Butter", "Salt to taste", "Fresh coriander leaves for garnish"]', '["Heat oil in a pan over medium heat. Add chopped onions and saut\u00e9 until golden brown.", "Add ginger-garlic paste and saut\u00e9 for another 2 minutes until fragrant.", "Pour in the tomato puree, turmeric, red chili powder, and salt. Cook until the mixture thickens and oil separates.", "Add the 1 lb fish fillets and coat well with the masala.", "Add half a cup of water, cover, and simmer until cooked through (about 15-20 minutes).", "Sprinkle garam masala and garnish with fresh coriander before serving."]', 0, 1);
