INSERT INTO recipes (id, title, category, cuisine, difficulty, time, servings, rating, reviews, image, description, ingredients, steps, featured, trending) VALUES ('25', 'Fish Tikka', 'Fish & Seafood Recipes', 'Global', 'medium', '45 mins', 4, 4.5, 492, 'https://images.unsplash.com/photo-1615141982883-c7da0e69f591?q=80&w=1470&auto=format&fit=crop', 'A delicious preparation of Fish Tikka, carefully crafted for the perfect meal.', '["1 lb Fish fillets", "2 large Onions, finely chopped", "2 Tomatoes, pureed", "1 tbsp Ginger-garlic paste", "1 tsp Turmeric powder", "1 tsp Red chili powder", "1 tsp Garam masala", "2 tbsp Oil or Butter", "Salt to taste", "Fresh coriander leaves for garnish"]', '["Heat oil in a pan over medium heat. Add chopped onions and saut\u00e9 until golden brown.", "Add ginger-garlic paste and saut\u00e9 for another 2 minutes until fragrant.", "Pour in the tomato puree, turmeric, red chili powder, and salt. Cook until the mixture thickens and oil separates.", "Add the 1 lb fish fillets and coat well with the masala.", "Add half a cup of water, cover, and simmer until cooked through (about 15-20 minutes).", "Sprinkle garam masala and garnish with fresh coriander before serving."]', 0, 0);
INSERT INTO recipes (id, title, category, cuisine, difficulty, time, servings, rating, reviews, image, description, ingredients, steps, featured, trending) VALUES ('26', 'Prawn Masala', 'Fish & Seafood Recipes', 'Global', 'medium', '45 mins', 4, 4.5, 83, 'https://images.unsplash.com/photo-1615141982883-c7da0e69f591?q=80&w=1470&auto=format&fit=crop', 'A delicious preparation of Prawn Masala, carefully crafted for the perfect meal.', '["1 lb Prawns, peeled and deveined", "2 large Onions, finely chopped", "2 Tomatoes, pureed", "1 tbsp Ginger-garlic paste", "1 tsp Turmeric powder", "1 tsp Red chili powder", "1 tsp Garam masala", "2 tbsp Oil or Butter", "Salt to taste", "Fresh coriander leaves for garnish"]', '["Heat oil in a pan over medium heat. Add chopped onions and saut\u00e9 until golden brown.", "Add ginger-garlic paste and saut\u00e9 for another 2 minutes until fragrant.", "Pour in the tomato puree, turmeric, red chili powder, and salt. Cook until the mixture thickens and oil separates.", "Add the 1 lb prawns and coat well with the masala.", "Add half a cup of water, cover, and simmer until cooked through (about 15-20 minutes).", "Sprinkle garam masala and garnish with fresh coriander before serving."]', 0, 0);
INSERT INTO recipes (id, title, category, cuisine, difficulty, time, servings, rating, reviews, image, description, ingredients, steps, featured, trending) VALUES ('27', 'Prawn Biryani', 'Fish & Seafood Recipes', 'Global', 'medium', '45 mins', 4, 4.5, 103, 'https://images.unsplash.com/photo-1615141982883-c7da0e69f591?q=80&w=1470&auto=format&fit=crop', 'A delicious preparation of Prawn Biryani, carefully crafted for the perfect meal.', '["1 lb Prawns, peeled and deveined", "2 cups Basmati rice, washed and soaked", "2 large Onions, thinly sliced", "1/2 cup Yogurt", "2 tbsp Ginger-garlic paste", "2 tbsp Biryani masala", "Whole spices (cardamom, cloves, cinnamon)", "Mint and coriander leaves", "3 tbsp Ghee or Oil"]', '["Marinate the 1 lb prawns with yogurt, ginger-garlic paste, and spices for 1 hour.", "In a large pot, heat ghee and fry the whole spices and sliced onions until golden brown.", "Add the marinated mixture and cook until the oil begins to separate.", "In a separate pot, boil water with salt and whole spices, then parboil the soaked basmati rice (about 70% cooked).", "Layer the parboiled rice over the cooked mixture. Sprinkle mint leaves and saffron milk.", "Cover tightly and cook on low heat (dum) for 20-25 minutes. Serve hot."]', 0, 0);
