INSERT INTO recipes (id, title, category, cuisine, difficulty, time, servings, rating, reviews, image, description, ingredients, steps, featured, trending) VALUES ('39', 'Chicken Burger', 'Fast Food / Snacks (Non-Veg)', 'Global', 'medium', '45 mins', 4, 4.5, 334, 'https://images.unsplash.com/photo-1604908176997-125f25cc6f3d?q=80&w=1613&auto=format&fit=crop', 'A delicious preparation of Chicken Burger, carefully crafted for the perfect meal.', '["Burger buns or Bread slices", "1 Patty or Filling (e.g., grilled chicken, vegetable patty)", "Lettuce leaves", "Tomato slices", "Onion rings", "Cheese slices", "2 tbsp Mayonnaise", "1 tbsp Ketchup or Mustard"]', '["Toast the buns or bread slices lightly on a buttered griddle.", "Cook the patty in a pan until golden brown and cooked through.", "Spread mayonnaise and ketchup on the toasted buns.", "Layer the lettuce, tomato, onion, and cooked patty.", "Place a cheese slice on top of the hot patty so it melts slightly.", "Close the burger/sandwich and serve immediately with a side of fries."]', 0, 0);
