INSERT INTO recipes (id, title, category, cuisine, difficulty, time, servings, rating, reviews, image, description, ingredients, steps, featured, trending) VALUES ('44', 'Meat Pizza', 'Fast Food / Snacks (Non-Veg)', 'Global', 'medium', '45 mins', 4, 4.5, 281, 'https://images.unsplash.com/photo-1513104890138-7c749659a591?q=80&w=1470&auto=format&fit=crop', 'A delicious preparation of Meat Pizza, carefully crafted for the perfect meal.', '["1 lb Pasta or Pizza dough", "2 cups Tomato sauce or Marinara", "2 cloves Garlic, minced", "1 cup Mozzarella cheese, shredded", "1/4 cup Parmesan cheese", "2 tbsp Olive oil", "Fresh basil leaves", "Salt and pepper", "Mixed vegetables"]', '["Prepare your pasta by boiling it in salted water, or roll out your pizza dough on a floured surface.", "In a pan, heat olive oil and saut\u00e9 minced garlic until fragrant.", "Add your protein (if using) and cook thoroughly. Then pour in the tomato sauce and simmer for 10 minutes.", "Combine the sauce with the cooked pasta, or spread it evenly over the pizza dough.", "Top generously with mozzarella and parmesan cheese.", "Bake or simmer until the cheese is melted, bubbly, and slightly golden.", "Garnish with fresh basil leaves and serve immediately."]', 0, 0);
