INSERT INTO recipes (id, title, category, cuisine, difficulty, time, servings, rating, reviews, image, description, ingredients, steps, featured, trending) VALUES ('52', 'Greek Salad', 'Salads & Light Dishes', 'Global', 'medium', '45 mins', 4, 4.5, 134, 'https://images.unsplash.com/photo-1512621776951-a57141f2eefd?q=80&w=1470&auto=format&fit=crop', 'A delicious preparation of Greek Salad, carefully crafted for the perfect meal.', '["4 cups Mixed salad greens (lettuce, spinach)", "1 cup Cherry tomatoes, halved", "1 Cucumber, sliced", "1/4 cup Red onion, thinly sliced", "3 tbsp Extra virgin olive oil", "1 tbsp Lemon juice or Vinegar", "Salt and freshly cracked black pepper", "Feta cheese, crumbled", "Kalamata olives"]', '["Wash and thoroughly dry all the salad greens and vegetables.", "In a large serving bowl, combine the greens, tomatoes, cucumber, and red onion.", "In a small jar, combine the olive oil, lemon juice, salt, and pepper. Shake vigorously to emulsify the dressing.", "Pour the dressing over the salad just before serving.", "Toss gently to ensure all ingredients are coated evenly."]', 0, 1);
