INSERT INTO recipes (id, title, category, cuisine, difficulty, time, servings, rating, reviews, image, description, ingredients, steps, featured, trending) VALUES ('57', 'Paneer Butter Masala', 'Indian Main Course (Veg)', 'Global', 'medium', '45 mins', 4, 4.5, 255, 'https://images.unsplash.com/photo-1585937421612-70a008356fbe?q=80&w=1472&auto=format&fit=crop', 'A delicious preparation of Paneer Butter Masala, carefully crafted for the perfect meal.', '["250g Paneer, cubed", "2 large Onions, finely chopped", "2 Tomatoes, pureed", "1 tbsp Ginger-garlic paste", "1 tsp Turmeric powder", "1 tsp Red chili powder", "1 tsp Garam masala", "2 tbsp Oil or Butter", "Salt to taste", "Fresh coriander leaves for garnish"]', '["Heat oil in a pan over medium heat. Add chopped onions and saut\u00e9 until golden brown.", "Add ginger-garlic paste and saut\u00e9 for another 2 minutes until fragrant.", "Pour in the tomato puree, turmeric, red chili powder, and salt. Cook until the mixture thickens and oil separates.", "Add the 250g paneer and coat well with the masala.", "Add half a cup of water, cover, and simmer until cooked through (about 15-20 minutes).", "Sprinkle garam masala and garnish with fresh coriander before serving."]', 0, 0);
