INSERT INTO recipes (id, title, category, cuisine, difficulty, time, servings, rating, reviews, image, description, ingredients, steps, featured, trending) VALUES ('67', 'Veg Biryani', 'Rice Dishes', 'Global', 'medium', '45 mins', 4, 4.5, 236, 'https://images.unsplash.com/photo-1631515243349-e0cb75fb8d3a?q=80&w=1488&auto=format&fit=crop', 'A delicious preparation of Veg Biryani, carefully crafted for the perfect meal.', '["Mixed vegetables", "2 cups Basmati rice, washed and soaked", "2 large Onions, thinly sliced", "1/2 cup Yogurt", "2 tbsp Ginger-garlic paste", "2 tbsp Biryani masala", "Whole spices (cardamom, cloves, cinnamon)", "Mint and coriander leaves", "3 tbsp Ghee or Oil"]', '["Marinate the mixed vegetables with yogurt, ginger-garlic paste, and spices for 1 hour.", "In a large pot, heat ghee and fry the whole spices and sliced onions until golden brown.", "Add the marinated mixture and cook until the oil begins to separate.", "In a separate pot, boil water with salt and whole spices, then parboil the soaked basmati rice (about 70% cooked).", "Layer the parboiled rice over the cooked mixture. Sprinkle mint leaves and saffron milk.", "Cover tightly and cook on low heat (dum) for 20-25 minutes. Serve hot."]', 0, 0);
