INSERT INTO recipes (id, title, category, cuisine, difficulty, time, servings, rating, reviews, image, description, ingredients, steps, featured, trending) VALUES ('72', 'Veg Hakka Noodles', 'Noodles & Pasta', 'Global', 'medium', '45 mins', 4, 4.5, 233, 'https://images.unsplash.com/photo-1626844131082-256783844137?q=80&w=1470&auto=format&fit=crop', 'A delicious preparation of Veg Hakka Noodles, carefully crafted for the perfect meal.', '["200g Noodles", "1 cup Mixed julienned vegetables (cabbage, carrot, bell pepper)", "2 cloves Garlic, finely chopped", "1 tbsp Soy sauce", "1 tbsp Chili sauce or Schezwan sauce", "1 tsp Vinegar", "2 tbsp Cooking oil", "Spring onions for garnish"]', '["Boil noodles according to package instructions. Drain, toss with a little oil, and set aside.", "Heat oil in a wok or large pan over high heat. Add garlic and stir-fry for 30 seconds.", "Add the julienned vegetables and stir-fry vigorously for 2-3 minutes so they remain crunchy.", "Add the sauces, vinegar, and a pinch of salt. Mix well.", "Toss the boiled noodles into the wok and mix thoroughly until coated with the sauces.", "Garnish with chopped spring onions and serve hot."]', 0, 0);
