INSERT INTO recipes (id, title, category, cuisine, difficulty, time, servings, rating, reviews, image, description, ingredients, steps, featured, trending) VALUES ('75', 'White Sauce Pasta', 'Noodles & Pasta', 'Global', 'medium', '45 mins', 4, 4.5, 436, 'https://images.unsplash.com/photo-1626844131082-256783844137?q=80&w=1470&auto=format&fit=crop', 'A delicious preparation of White Sauce Pasta, carefully crafted for the perfect meal.', '["1 lb Pasta or Pizza dough", "2 cups Tomato sauce or Marinara", "2 cloves Garlic, minced", "1 cup Mozzarella cheese, shredded", "1/4 cup Parmesan cheese", "2 tbsp Olive oil", "Fresh basil leaves", "Salt and pepper"]', '["Prepare your pasta by boiling it in salted water, or roll out your pizza dough on a floured surface.", "In a pan, heat olive oil and saut\u00e9 minced garlic until fragrant.", "Add your protein (if using) and cook thoroughly. Then pour in the tomato sauce and simmer for 10 minutes.", "Combine the sauce with the cooked pasta, or spread it evenly over the pizza dough.", "Top generously with mozzarella and parmesan cheese.", "Bake or simmer until the cheese is melted, bubbly, and slightly golden.", "Garnish with fresh basil leaves and serve immediately."]', 0, 1);
INSERT INTO recipes (id, title, category, cuisine, difficulty, time, servings, rating, reviews, image, description, ingredients, steps, featured, trending) VALUES ('76', 'Red Sauce Pasta', 'Noodles & Pasta', 'Global', 'medium', '45 mins', 4, 4.5, 97, 'https://images.unsplash.com/photo-1626844131082-256783844137?q=80&w=1470&auto=format&fit=crop', 'A delicious preparation of Red Sauce Pasta, carefully crafted for the perfect meal.', '["1 lb Pasta or Pizza dough", "2 cups Tomato sauce or Marinara", "2 cloves Garlic, minced", "1 cup Mozzarella cheese, shredded", "1/4 cup Parmesan cheese", "2 tbsp Olive oil", "Fresh basil leaves", "Salt and pepper"]', '["Prepare your pasta by boiling it in salted water, or roll out your pizza dough on a floured surface.", "In a pan, heat olive oil and saut\u00e9 minced garlic until fragrant.", "Add your protein (if using) and cook thoroughly. Then pour in the tomato sauce and simmer for 10 minutes.", "Combine the sauce with the cooked pasta, or spread it evenly over the pizza dough.", "Top generously with mozzarella and parmesan cheese.", "Bake or simmer until the cheese is melted, bubbly, and slightly golden.", "Garnish with fresh basil leaves and serve immediately."]', 0, 0);
INSERT INTO recipes (id, title, category, cuisine, difficulty, time, servings, rating, reviews, image, description, ingredients, steps, featured, trending) VALUES ('77', 'Masala Dosa', 'Breads & Breakfast', 'Global', 'medium', '45 mins', 4, 4.5, 480, 'https://images.unsplash.com/photo-1585937421612-70a008356fbe?q=80&w=1472&auto=format&fit=crop', 'A delicious preparation of Masala Dosa, carefully crafted for the perfect meal.', '["Mixed vegetables", "2 large Onions, finely chopped", "2 Tomatoes, pureed", "1 tbsp Ginger-garlic paste", "1 tsp Turmeric powder", "1 tsp Red chili powder", "1 tsp Garam masala", "2 tbsp Oil or Butter", "Salt to taste", "Fresh coriander leaves for garnish"]', '["Heat oil in a pan over medium heat. Add chopped onions and saut\u00e9 until golden brown.", "Add ginger-garlic paste and saut\u00e9 for another 2 minutes until fragrant.", "Pour in the tomato puree, turmeric, red chili powder, and salt. Cook until the mixture thickens and oil separates.", "Add the mixed vegetables and coat well with the masala.", "Add half a cup of water, cover, and simmer until cooked through (about 15-20 minutes).", "Sprinkle garam masala and garnish with fresh coriander before serving."]', 0, 0);
INSERT INTO recipes (id, title, category, cuisine, difficulty, time, servings, rating, reviews, image, description, ingredients, steps, featured, trending) VALUES ('78', 'Idli', 'Breads & Breakfast', 'Global', 'medium', '45 mins', 4, 4.5, 80, 'https://images.unsplash.com/photo-1509440159596-0249088772ff?q=80&w=1472&auto=format&fit=crop', 'A delicious preparation of Idli, carefully crafted for the perfect meal.', '["Mixed vegetables", "2 tbsp Cooking Oil or Butter", "1 Onion, finely chopped", "2 cloves Garlic, minced", "Chef''s special spice blend", "Fresh herbs for garnish", "Salt and pepper to taste"]', '["Prepare all ingredients by washing, peeling, and chopping as necessary.", "Heat oil or butter in a pan over medium heat. Saut\u00e9 the onions and garlic until fragrant.", "Add the main ingredient and cook until browned on all sides.", "Stir in the spices and season generously with salt and pepper.", "Add a splash of water or broth, cover, and simmer until fully cooked.", "Plate beautifully, garnish with fresh herbs, and serve hot."]', 0, 1);
