INSERT INTO recipes (id, title, category, cuisine, difficulty, time, servings, rating, reviews, image, description, ingredients, steps, featured, trending) VALUES ('90', 'Tomato Soup', 'Soups', 'Global', 'medium', '45 mins', 4, 4.5, 162, 'https://images.unsplash.com/photo-1547592180-85f173990554?q=80&w=1470&auto=format&fit=crop', 'A delicious preparation of Tomato Soup, carefully crafted for the perfect meal.', '["4 cups Vegetable or Chicken broth", "1 Onion, finely chopped", "2 cloves Garlic, minced", "2 Carrots, diced", "2 sticks Celery, diced", "1 tbsp Olive oil", "2 cups chopped mixed vegetables (potato, corn, peas)", "Salt and pepper to taste"]', '["Heat olive oil in a large soup pot over medium heat.", "Add the chopped onions, garlic, carrots, and celery. Saut\u00e9 for 5-7 minutes until softened.", "Add the main ingredient and pour in the broth.", "Bring the soup to a boil, then reduce the heat, cover, and simmer for 25-30 minutes.", "Season with salt and pepper. For a smoother texture, blend a portion of the soup.", "Serve hot with crusty bread."]', 0, 0);
INSERT INTO recipes (id, title, category, cuisine, difficulty, time, servings, rating, reviews, image, description, ingredients, steps, featured, trending) VALUES ('91', 'Sweet Corn Soup', 'Soups', 'Global', 'medium', '45 mins', 4, 4.5, 420, 'https://images.unsplash.com/photo-1547592180-85f173990554?q=80&w=1470&auto=format&fit=crop', 'A delicious preparation of Sweet Corn Soup, carefully crafted for the perfect meal.', '["4 cups Vegetable or Chicken broth", "1 Onion, finely chopped", "2 cloves Garlic, minced", "2 Carrots, diced", "2 sticks Celery, diced", "1 tbsp Olive oil", "2 cups chopped mixed vegetables (potato, corn, peas)", "Salt and pepper to taste"]', '["Heat olive oil in a large soup pot over medium heat.", "Add the chopped onions, garlic, carrots, and celery. Saut\u00e9 for 5-7 minutes until softened.", "Add the main ingredient and pour in the broth.", "Bring the soup to a boil, then reduce the heat, cover, and simmer for 25-30 minutes.", "Season with salt and pepper. For a smoother texture, blend a portion of the soup.", "Serve hot with crusty bread."]', 0, 0);
