INSERT INTO recipes (id, title, category, cuisine, difficulty, time, servings, rating, reviews, image, description, ingredients, steps, featured, trending) VALUES ('94', 'Gulab Jamun', 'Desserts', 'Global', 'medium', '45 mins', 4, 4.5, 127, 'https://images.unsplash.com/photo-1563805042-7684c8a9e1cb?q=80&w=1527&auto=format&fit=crop', 'A delicious preparation of Gulab Jamun, carefully crafted for the perfect meal.', '["Mixed vegetables", "2 tbsp Cooking Oil or Butter", "1 Onion, finely chopped", "2 cloves Garlic, minced", "Chef''s special spice blend", "Fresh herbs for garnish", "Salt and pepper to taste"]', '["Prepare all ingredients by washing, peeling, and chopping as necessary.", "Heat oil or butter in a pan over medium heat. Saut\u00e9 the onions and garlic until fragrant.", "Add the main ingredient and cook until browned on all sides.", "Stir in the spices and season generously with salt and pepper.", "Add a splash of water or broth, cover, and simmer until fully cooked.", "Plate beautifully, garnish with fresh herbs, and serve hot."]', 0, 1);
INSERT INTO recipes (id, title, category, cuisine, difficulty, time, servings, rating, reviews, image, description, ingredients, steps, featured, trending) VALUES ('95', 'Rasgulla', 'Desserts', 'Global', 'medium', '45 mins', 4, 4.5, 254, 'https://images.unsplash.com/photo-1563805042-7684c8a9e1cb?q=80&w=1527&auto=format&fit=crop', 'A delicious preparation of Rasgulla, carefully crafted for the perfect meal.', '["Mixed vegetables", "2 tbsp Cooking Oil or Butter", "1 Onion, finely chopped", "2 cloves Garlic, minced", "Chef''s special spice blend", "Fresh herbs for garnish", "Salt and pepper to taste"]', '["Prepare all ingredients by washing, peeling, and chopping as necessary.", "Heat oil or butter in a pan over medium heat. Saut\u00e9 the onions and garlic until fragrant.", "Add the main ingredient and cook until browned on all sides.", "Stir in the spices and season generously with salt and pepper.", "Add a splash of water or broth, cover, and simmer until fully cooked.", "Plate beautifully, garnish with fresh herbs, and serve hot."]', 0, 0);
