INSERT INTO recipes (id, title, category, cuisine, difficulty, time, servings, rating, reviews, image, description, ingredients, steps, featured, trending) VALUES ('97', 'Kheer', 'Desserts', 'Global', 'medium', '45 mins', 4, 4.5, 19, 'https://images.unsplash.com/photo-1563805042-7684c8a9e1cb?q=80&w=1527&auto=format&fit=crop', 'A delicious preparation of Kheer, carefully crafted for the perfect meal.', '["4 cups Whole milk", "1/2 cup Sugar", "1/4 cup Basmati rice, soaked", "1 tsp Vanilla extract or Cardamom powder", "2 tbsp Chopped nuts (almonds, pistachios)", "Mixed vegetables"]', '["In a heavy-bottomed saucepan, bring the milk to a gentle boil.", "Add your base ingredient (like soaked rice or pre-mixed custard powder slurry).", "Reduce the heat to low and simmer, stirring continuously to prevent sticking.", "Once the mixture thickens to the desired consistency, stir in the sugar and flavor extracts.", "Continue to cook for another 5 minutes until the sugar is fully dissolved.", "Remove from heat, garnish with chopped nuts, and chill in the refrigerator before serving."]', 0, 1);
INSERT INTO recipes (id, title, category, cuisine, difficulty, time, servings, rating, reviews, image, description, ingredients, steps, featured, trending) VALUES ('98', 'Ice Cream', 'Desserts', 'Global', 'medium', '45 mins', 4, 4.5, 172, 'https://images.unsplash.com/photo-1563805042-7684c8a9e1cb?q=80&w=1527&auto=format&fit=crop', 'A delicious preparation of Ice Cream, carefully crafted for the perfect meal.', '["4 cups Whole milk", "1/2 cup Sugar", "1/4 cup Cornstarch or Custard powder (if making custard)", "1 tsp Vanilla extract or Cardamom powder", "2 tbsp Chopped nuts (almonds, pistachios)", "Base flavor ingredient"]', '["In a heavy-bottomed saucepan, bring the milk to a gentle boil.", "Add your base ingredient (like soaked rice or pre-mixed custard powder slurry).", "Reduce the heat to low and simmer, stirring continuously to prevent sticking.", "Once the mixture thickens to the desired consistency, stir in the sugar and flavor extracts.", "Continue to cook for another 5 minutes until the sugar is fully dissolved.", "Remove from heat, garnish with chopped nuts, and chill in the refrigerator before serving."]', 0, 0);
INSERT INTO recipes (id, title, category, cuisine, difficulty, time, servings, rating, reviews, image, description, ingredients, steps, featured, trending) VALUES ('99', 'Brownies', 'Desserts', 'Global', 'medium', '45 mins', 4, 4.5, 421, 'https://images.unsplash.com/photo-1578985545062-69928b1d9587?q=80&w=1389&auto=format&fit=crop', 'A delicious preparation of Brownies, carefully crafted for the perfect meal.', '["2 cups All-purpose flour", "1 cup Granulated sugar", "1/2 cup Butter, softened", "2 Large eggs", "1 cup Milk", "1 tsp Baking powder", "1 tsp Vanilla extract", "Pinch of salt", "1/2 cup Cocoa powder"]', '["Preheat your oven to 350\u00b0F (175\u00b0C) and grease a baking pan.", "In a large bowl, cream together the softened butter and sugar until light and fluffy.", "Beat in the eggs one at a time, then stir in the vanilla extract.", "In a separate bowl, whisk together the flour, baking powder, and salt.", "Gradually mix the dry ingredients into the wet mixture, alternating with milk.", "Pour the batter into the prepared pan and bake for 30-35 minutes until a toothpick inserted comes out clean.", "Allow to cool completely before slicing or frosting."]', 0, 0);
INSERT INTO recipes (id, title, category, cuisine, difficulty, time, servings, rating, reviews, image, description, ingredients, steps, featured, trending) VALUES ('100', 'Cakes (Chocolate, Vanilla)', 'Desserts', 'Global', 'medium', '45 mins', 4, 4.5, 97, 'https://images.unsplash.com/photo-1578985545062-69928b1d9587?q=80&w=1389&auto=format&fit=crop', 'A delicious preparation of Cakes (Chocolate, Vanilla), carefully crafted for the perfect meal.', '["2 cups All-purpose flour", "1 cup Granulated sugar", "1/2 cup Butter, softened", "2 Large eggs", "1 cup Milk", "1 tsp Baking powder", "1 tsp Vanilla extract", "Pinch of salt", "1/2 cup Cocoa powder"]', '["Preheat your oven to 350\u00b0F (175\u00b0C) and grease a baking pan.", "In a large bowl, cream together the softened butter and sugar until light and fluffy.", "Beat in the eggs one at a time, then stir in the vanilla extract.", "In a separate bowl, whisk together the flour, baking powder, and salt.", "Gradually mix the dry ingredients into the wet mixture, alternating with milk.", "Pour the batter into the prepared pan and bake for 30-35 minutes until a toothpick inserted comes out clean.", "Allow to cool completely before slicing or frosting."]', 0, 0);
INSERT INTO recipes (id, title, category, cuisine, difficulty, time, servings, rating, reviews, image, description, ingredients, steps, featured, trending) VALUES ('101', 'Veg Pizza', 'International Veg Dishes', 'Global', 'medium', '45 mins', 4, 4.5, 358, 'https://images.unsplash.com/photo-1604382354936-07c5d9983bd3?q=80&w=1470&auto=format&fit=crop', 'A delicious preparation of Veg Pizza, carefully crafted for the perfect meal.', '["1 lb Pasta or Pizza dough", "2 cups Tomato sauce or Marinara", "2 cloves Garlic, minced", "1 cup Mozzarella cheese, shredded", "1/4 cup Parmesan cheese", "2 tbsp Olive oil", "Fresh basil leaves", "Salt and pepper"]', '["Prepare your pasta by boiling it in salted water, or roll out your pizza dough on a floured surface.", "In a pan, heat olive oil and saut\u00e9 minced garlic until fragrant.", "Add your protein (if using) and cook thoroughly. Then pour in the tomato sauce and simmer for 10 minutes.", "Combine the sauce with the cooked pasta, or spread it evenly over the pizza dough.", "Top generously with mozzarella and parmesan cheese.", "Bake or simmer until the cheese is melted, bubbly, and slightly golden.", "Garnish with fresh basil leaves and serve immediately."]', 0, 0);
