INSERT INTO recipes (id, title, category, cuisine, difficulty, time, servings, rating, reviews, image, description, ingredients, steps, featured, trending) VALUES ('115', 'Brownies', 'Cakes & Pastries', 'Global', 'medium', '45 mins', 4, 4.5, 400, 'https://images.unsplash.com/photo-1578985545062-69928b1d9587?q=80&w=1389&auto=format&fit=crop', 'A delicious preparation of Brownies, carefully crafted for the perfect meal.', '["2 cups All-purpose flour", "1 cup Granulated sugar", "1/2 cup Butter, softened", "2 Large eggs", "1 cup Milk", "1 tsp Baking powder", "1 tsp Vanilla extract", "Pinch of salt", "1/2 cup Cocoa powder"]', '["Preheat your oven to 350\u00b0F (175\u00b0C) and grease a baking pan.", "In a large bowl, cream together the softened butter and sugar until light and fluffy.", "Beat in the eggs one at a time, then stir in the vanilla extract.", "In a separate bowl, whisk together the flour, baking powder, and salt.", "Gradually mix the dry ingredients into the wet mixture, alternating with milk.", "Pour the batter into the prepared pan and bake for 30-35 minutes until a toothpick inserted comes out clean.", "Allow to cool completely before slicing or frosting."]', 0, 1);
INSERT INTO recipes (id, title, category, cuisine, difficulty, time, servings, rating, reviews, image, description, ingredients, steps, featured, trending) VALUES ('116', 'Muffins', 'Cakes & Pastries', 'Global', 'medium', '45 mins', 4, 4.5, 431, 'https://images.unsplash.com/photo-1578985545062-69928b1d9587?q=80&w=1389&auto=format&fit=crop', 'A delicious preparation of Muffins, carefully crafted for the perfect meal.', '["2 cups All-purpose flour", "1 cup Granulated sugar", "1/2 cup Butter, softened", "2 Large eggs", "1 cup Milk", "1 tsp Baking powder", "1 tsp Vanilla extract", "Pinch of salt"]', '["Preheat your oven to 350\u00b0F (175\u00b0C) and grease a baking pan.", "In a large bowl, cream together the softened butter and sugar until light and fluffy.", "Beat in the eggs one at a time, then stir in the vanilla extract.", "In a separate bowl, whisk together the flour, baking powder, and salt.", "Gradually mix the dry ingredients into the wet mixture, alternating with milk.", "Pour the batter into the prepared pan and bake for 30-35 minutes until a toothpick inserted comes out clean.", "Allow to cool completely before slicing or frosting."]', 0, 0);
INSERT INTO recipes (id, title, category, cuisine, difficulty, time, servings, rating, reviews, image, description, ingredients, steps, featured, trending) VALUES ('117', 'Rice Pudding (Kheer)', 'Puddings & Custards', 'Global', 'medium', '45 mins', 4, 4.5, 327, 'https://images.unsplash.com/photo-1631515243349-e0cb75fb8d3a?q=80&w=1488&auto=format&fit=crop', 'A delicious preparation of Rice Pudding (Kheer), carefully crafted for the perfect meal.', '["Mixed vegetables", "2 cups Basmati rice, washed and soaked", "2 large Onions, thinly sliced", "1/2 cup Yogurt", "2 tbsp Ginger-garlic paste", "2 tbsp Biryani masala", "Whole spices (cardamom, cloves, cinnamon)", "Mint and coriander leaves", "3 tbsp Ghee or Oil"]', '["Marinate the mixed vegetables with yogurt, ginger-garlic paste, and spices for 1 hour.", "In a large pot, heat ghee and fry the whole spices and sliced onions until golden brown.", "Add the marinated mixture and cook until the oil begins to separate.", "In a separate pot, boil water with salt and whole spices, then parboil the soaked basmati rice (about 70% cooked).", "Layer the parboiled rice over the cooked mixture. Sprinkle mint leaves and saffron milk.", "Cover tightly and cook on low heat (dum) for 20-25 minutes. Serve hot."]', 0, 0);
INSERT INTO recipes (id, title, category, cuisine, difficulty, time, servings, rating, reviews, image, description, ingredients, steps, featured, trending) VALUES ('118', 'Custard', 'Puddings & Custards', 'Global', 'medium', '45 mins', 4, 4.5, 59, 'https://images.unsplash.com/photo-1563805042-7684c8a9e1cb?q=80&w=1527&auto=format&fit=crop', 'A delicious preparation of Custard, carefully crafted for the perfect meal.', '["4 cups Whole milk", "1/2 cup Sugar", "1/4 cup Cornstarch or Custard powder (if making custard)", "1 tsp Vanilla extract or Cardamom powder", "2 tbsp Chopped nuts (almonds, pistachios)", "Base flavor ingredient"]', '["In a heavy-bottomed saucepan, bring the milk to a gentle boil.", "Add your base ingredient (like soaked rice or pre-mixed custard powder slurry).", "Reduce the heat to low and simmer, stirring continuously to prevent sticking.", "Once the mixture thickens to the desired consistency, stir in the sugar and flavor extracts.", "Continue to cook for another 5 minutes until the sugar is fully dissolved.", "Remove from heat, garnish with chopped nuts, and chill in the refrigerator before serving."]', 0, 0);
