INSERT INTO recipes (id, title, category, cuisine, difficulty, time, servings, rating, reviews, image, description, ingredients, steps, featured, trending) VALUES ('124', 'Gelato', 'Frozen Desserts', 'Global', 'medium', '45 mins', 4, 4.5, 458, 'https://images.unsplash.com/photo-1563805042-7684c8a9e1cb?q=80&w=1527&auto=format&fit=crop', 'A delicious preparation of Gelato, carefully crafted for the perfect meal.', '["Mixed vegetables", "2 tbsp Cooking Oil or Butter", "1 Onion, finely chopped", "2 cloves Garlic, minced", "Chef''s special spice blend", "Fresh herbs for garnish", "Salt and pepper to taste"]', '["Prepare all ingredients by washing, peeling, and chopping as necessary.", "Heat oil or butter in a pan over medium heat. Saut\u00e9 the onions and garlic until fragrant.", "Add the main ingredient and cook until browned on all sides.", "Stir in the spices and season generously with salt and pepper.", "Add a splash of water or broth, cover, and simmer until fully cooked.", "Plate beautifully, garnish with fresh herbs, and serve hot."]', 0, 0);
