INSERT INTO recipes (id, title, category, cuisine, difficulty, time, servings, rating, reviews, image, description, ingredients, steps, featured, trending) VALUES ('140', 'Apple Pie', 'Pies & Tarts', 'Global', 'medium', '45 mins', 4, 4.5, 87, 'https://images.unsplash.com/photo-1587241321921-91a834d6d191?q=80&w=1470&auto=format&fit=crop', 'A delicious preparation of Apple Pie, carefully crafted for the perfect meal.', '["2 cups All-purpose flour", "1 cup Granulated sugar", "1/2 cup Butter, softened", "2 Large eggs", "1 cup Milk", "1 tsp Baking powder", "1 tsp Vanilla extract", "Pinch of salt"]', '["Preheat your oven to 350\u00b0F (175\u00b0C) and grease a baking pan.", "In a large bowl, cream together the softened butter and sugar until light and fluffy.", "Beat in the eggs one at a time, then stir in the vanilla extract.", "In a separate bowl, whisk together the flour, baking powder, and salt.", "Gradually mix the dry ingredients into the wet mixture, alternating with milk.", "Pour the batter into the prepared pan and bake for 30-35 minutes until a toothpick inserted comes out clean.", "Allow to cool completely before slicing or frosting."]', 0, 0);
