INSERT INTO recipes (id, title, category, cuisine, difficulty, time, servings, rating, reviews, image, description, ingredients, steps, featured, trending) VALUES ('160', 'Fruit Salad with Cream', 'Fruit-Based Desserts', 'Global', 'medium', '45 mins', 4, 4.5, 318, 'https://images.unsplash.com/photo-1512621776951-a57141f2eefd?q=80&w=1470&auto=format&fit=crop', 'A delicious preparation of Fruit Salad with Cream, carefully crafted for the perfect meal.', '["4 cups Mixed salad greens (lettuce, spinach)", "1 cup Cherry tomatoes, halved", "1 Cucumber, sliced", "1/4 cup Red onion, thinly sliced", "3 tbsp Extra virgin olive oil", "1 tbsp Lemon juice or Vinegar", "Salt and freshly cracked black pepper"]', '["Wash and thoroughly dry all the salad greens and vegetables.", "In a large serving bowl, combine the greens, tomatoes, cucumber, and red onion.", "In a small jar, combine the olive oil, lemon juice, salt, and pepper. Shake vigorously to emulsify the dressing.", "Pour the dressing over the salad just before serving.", "Toss gently to ensure all ingredients are coated evenly."]', 0, 0);
INSERT INTO recipes (id, title, category, cuisine, difficulty, time, servings, rating, reviews, image, description, ingredients, steps, featured, trending) VALUES ('161', 'Fruit Custard', 'Fruit-Based Desserts', 'Global', 'medium', '45 mins', 4, 4.5, 114, 'https://images.unsplash.com/photo-1563805042-7684c8a9e1cb?q=80&w=1527&auto=format&fit=crop', 'A delicious preparation of Fruit Custard, carefully crafted for the perfect meal.', '["4 cups Whole milk", "1/2 cup Sugar", "1/4 cup Cornstarch or Custard powder (if making custard)", "1 tsp Vanilla extract or Cardamom powder", "2 tbsp Chopped nuts (almonds, pistachios)", "Base flavor ingredient"]', '["In a heavy-bottomed saucepan, bring the milk to a gentle boil.", "Add your base ingredient (like soaked rice or pre-mixed custard powder slurry).", "Reduce the heat to low and simmer, stirring continuously to prevent sticking.", "Once the mixture thickens to the desired consistency, stir in the sugar and flavor extracts.", "Continue to cook for another 5 minutes until the sugar is fully dissolved.", "Remove from heat, garnish with chopped nuts, and chill in the refrigerator before serving."]', 0, 0);
INSERT INTO recipes (id, title, category, cuisine, difficulty, time, servings, rating, reviews, image, description, ingredients, steps, featured, trending) VALUES ('162', 'Mango Mousse', 'Fruit-Based Desserts', 'Global', 'medium', '45 mins', 4, 4.5, 176, 'https://images.unsplash.com/photo-1563805042-7684c8a9e1cb?q=80&w=1527&auto=format&fit=crop', 'A delicious preparation of Mango Mousse, carefully crafted for the perfect meal.', '["Mixed vegetables", "2 tbsp Cooking Oil or Butter", "1 Onion, finely chopped", "2 cloves Garlic, minced", "Chef''s special spice blend", "Fresh herbs for garnish", "Salt and pepper to taste"]', '["Prepare all ingredients by washing, peeling, and chopping as necessary.", "Heat oil or butter in a pan over medium heat. Saut\u00e9 the onions and garlic until fragrant.", "Add the main ingredient and cook until browned on all sides.", "Stir in the spices and season generously with salt and pepper.", "Add a splash of water or broth, cover, and simmer until fully cooked.", "Plate beautifully, garnish with fresh herbs, and serve hot."]', 0, 0);
INSERT INTO recipes (id, title, category, cuisine, difficulty, time, servings, rating, reviews, image, description, ingredients, steps, featured, trending) VALUES ('163', 'Strawberry Shortcake', 'Fruit-Based Desserts', 'Global', 'medium', '45 mins', 4, 4.5, 25, 'https://images.unsplash.com/photo-1578985545062-69928b1d9587?q=80&w=1389&auto=format&fit=crop', 'A delicious preparation of Strawberry Shortcake, carefully crafted for the perfect meal.', '["2 cups All-purpose flour", "1 cup Granulated sugar", "1/2 cup Butter, softened", "2 Large eggs", "1 cup Milk", "1 tsp Baking powder", "1 tsp Vanilla extract", "Pinch of salt"]', '["Preheat your oven to 350\u00b0F (175\u00b0C) and grease a baking pan.", "In a large bowl, cream together the softened butter and sugar until light and fluffy.", "Beat in the eggs one at a time, then stir in the vanilla extract.", "In a separate bowl, whisk together the flour, baking powder, and salt.", "Gradually mix the dry ingredients into the wet mixture, alternating with milk.", "Pour the batter into the prepared pan and bake for 30-35 minutes until a toothpick inserted comes out clean.", "Allow to cool completely before slicing or frosting."]', 0, 0);
