CREATE TABLE IF NOT EXISTS categories ( id INTEGER PRIMARY KEY AUTOINCREMENT, name VARCHAR(255) NOT NULL UNIQUE, icon VARCHAR(255) );
CREATE TABLE IF NOT EXISTS users ( id VARCHAR(255) PRIMARY KEY, name VARCHAR(255) NOT NULL, email VARCHAR(255) NOT NULL UNIQUE, password_hash VARCHAR(255) NOT NULL, registration_date DATETIME DEFAULT CURRENT_TIMESTAMP );
CREATE TABLE IF NOT EXISTS search_history ( id INTEGER PRIMARY KEY AUTOINCREMENT, user_id VARCHAR(255) NOT NULL, search_query VARCHAR(255) NOT NULL, timestamp DATETIME DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY(user_id) REFERENCES users(id) );
CREATE TABLE IF NOT EXISTS recipes ( id VARCHAR(255) PRIMARY KEY, title VARCHAR(255) NOT NULL, category VARCHAR(255), cuisine VARCHAR(255), difficulty VARCHAR(50), time VARCHAR(50), servings INTEGER, rating FLOAT, reviews INTEGER, image TEXT, description TEXT, ingredients TEXT, steps TEXT, featured BOOLEAN, trending BOOLEAN, FOREIGN KEY(category) REFERENCES categories(name) );
